package com.example.ecomsearch.service;

import com.example.ecomsearch.dto.FacetBucket;
import com.example.ecomsearch.dto.ProductSearchRequest;
import com.example.ecomsearch.dto.ProductSearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQueryLog;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.admin.indices.create.CreateIndexRequest;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.admin.indices.exists.indices.GetIndexRequest;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.IndicesClient;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.Aggregation;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.ParsedStringTerms;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;
import org.elasticsearch.action.support.master.AcknowledgedResponse;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private static final String PRODUCT_INDEX = "products";
    private static final String SEARCH_LOG_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void initializeIndices() throws IOException {
        createProductIndexIfAbsent();
        createSearchLogIndexIfAbsent();
    }

    public void indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            bulkRequest.add(new IndexRequest(PRODUCT_INDEX)
                    .id(product.getId())
                    .source(objectMapper.writeValueAsString(product), XContentType.JSON));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new IOException("Bulk indexing failed: " + response.buildFailureMessage());
        }
    }

    public ProductSearchResponse search(ProductSearchRequest request) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCT_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().trim().isEmpty()) {
            MultiMatchQueryBuilder multiMatchQuery = QueryBuilders.multiMatchQuery(request.getQuery(), "name", "description", "brand", "category", "tags")
                    .field("name", 3.0f)
                    .field("description", 2.0f)
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness("AUTO");
            boolQuery.must(multiMatchQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("category.keyword", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("brand.keyword", request.getBrand()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price")
                    .from(request.getMinPrice() != null ? request.getMinPrice() : null)
                    .to(request.getMaxPrice() != null ? request.getMaxPrice() : null));
        }

        if (request.getAttributes() != null) {
            for (Map.Entry<String, String> entry : request.getAttributes().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + entry.getKey() + ".keyword", entry.getValue()));
            }
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(request.getPage() * request.getSize());
        sourceBuilder.size(request.getSize());
        sourceBuilder.sort("_score", SortOrder.DESC);
        sourceBuilder.sort("rating", SortOrder.DESC);

        sourceBuilder.aggregation(AggregationBuilders.terms("brandFacet").field("brand.keyword").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("categoryFacet").field("category.keyword").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("tagsFacet").field("tags.keyword").size(20));

        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name");
        highlightBuilder.field("description");
        sourceBuilder.highlighter(highlightBuilder);

        searchRequest.source(sourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = Arrays.stream(response.getHits().getHits())
                .map(this::mapHitToProduct)
                .collect(Collectors.toList());

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        facets.put("brand", extractFacet(response, "brandFacet"));
        facets.put("category", extractFacet(response, "categoryFacet"));
        facets.put("tags", extractFacet(response, "tagsFacet"));

        ProductSearchResponse searchResponse = new ProductSearchResponse(
                response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : products.size(),
                response.getTook().getMillis(),
                products,
                facets
        );

        logSearchQuery(request, searchResponse);
        return searchResponse;
    }

    public void logSearchQuery(ProductSearchRequest request, ProductSearchResponse response) throws IOException {
        Map<String, String> filters = new HashMap<>();
        if (request.getCategory() != null) filters.put("category", request.getCategory());
        if (request.getBrand() != null) filters.put("brand", request.getBrand());
        if (request.getAttributes() != null) filters.putAll(request.getAttributes());

        SearchQueryLog log = new SearchQueryLog(
                UUID.randomUUID().toString(),
                request.getQuery(),
                filters,
                request.getPage(),
                request.getSize(),
                Instant.now(),
                response.getTookMs(),
                response.getTotalHits()
        );

        IndexRequest indexRequest = new IndexRequest(SEARCH_LOG_INDEX)
                .id(log.getId())
                .source(objectMapper.writeValueAsString(log), XContentType.JSON);

        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    private Product mapHitToProduct(SearchHit hit) {
        return objectMapper.convertValue(hit.getSourceAsMap(), Product.class);
    }

    private List<FacetBucket> extractFacet(SearchResponse response, String aggName) {
        Aggregation aggregation = response.getAggregations().get(aggName);
        if (aggregation instanceof ParsedStringTerms) {
            ParsedStringTerms terms = (ParsedStringTerms) aggregation;
            return terms.getBuckets().stream()
                    .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()))
                    .collect(Collectors.toList());
        } else if (aggregation instanceof Terms) {
            Terms terms = (Terms) aggregation;
            return terms.getBuckets().stream()
                    .map(bucket -> new FacetBucket(bucket.getKeyAsString(), bucket.getDocCount()))
                    .collect(Collectors.toList());
        }
        return Collections.emptyList();
    }

    private void createProductIndexIfAbsent() throws IOException {
        IndicesClient indicesClient = client.indices();
        GetIndexRequest request = new GetIndexRequest().indices(PRODUCT_INDEX);
        boolean exists = indicesClient.exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(PRODUCT_INDEX);
            createIndexRequest.source("{\n" +
                    "  \"settings\": {\n" +
                    "    \"number_of_shards\": 1,\n" +
                    "    \"number_of_replicas\": 1,\n" +
                    "    \"analysis\": {\n" +
                    "      \"analyzer\": {\n" +
                    "        \"product_analyzer\": {\n" +
                    "          \"type\": \"standard\"\n" +
                    "        }\n" +
                    "      }\n" +
                    "    }\n" +
                    "  },\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"id\": {\"type\": \"keyword\"},\n" +
                    "      \"sku\": {\"type\": \"keyword\"},\n" +
                    "      \"name\": {\n" +
                    "        \"type\": \"text\",\n" +
                    "        \"analyzer\": \"product_analyzer\",\n" +
                    "        \"fields\": {\"keyword\": {\"type\": \"keyword\"}}\n" +
                    "      },\n" +
                    "      \"description\": {\"type\": \"text\", \"analyzer\": \"product_analyzer\"},\n" +
                    "      \"brand\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "      \"category\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "      \"price\": {\"type\": \"double\"},\n" +
                    "      \"inventory\": {\"type\": \"integer\"},\n" +
                    "      \"rating\": {\"type\": \"double\"},\n" +
                    "      \"tags\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "      \"attributes\": {\"type\": \"object\", \"dynamic\": true}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            indicesClient.create(createIndexRequest, RequestOptions.DEFAULT);
        }
    }

    private void createSearchLogIndexIfAbsent() throws IOException {
        IndicesClient indicesClient = client.indices();
        GetIndexRequest request = new GetIndexRequest().indices(SEARCH_LOG_INDEX);
        boolean exists = indicesClient.exists(request, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest(SEARCH_LOG_INDEX);
            createIndexRequest.source("{\n" +
                    "  \"settings\": {\n" +
                    "    \"number_of_shards\": 1,\n" +
                    "    \"number_of_replicas\": 1\n" +
                    "  },\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"id\": {\"type\": \"keyword\"},\n" +
                    "      \"query\": {\"type\": \"text\", \"fields\": {\"keyword\": {\"type\": \"keyword\"}}},\n" +
                    "      \"filters\": {\"type\": \"object\", \"dynamic\": true},\n" +
                    "      \"page\": {\"type\": \"integer\"},\n" +
                    "      \"size\": {\"type\": \"integer\"},\n" +
                    "      \"searchedAt\": {\"type\": \"date\"},\n" +
                    "      \"tookMs\": {\"type\": \"long\"},\n" +
                    "      \"totalHits\": {\"type\": \"long\"}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            indicesClient.create(createIndexRequest, RequestOptions.DEFAULT);
        }
    }
}

package com.example.ecomsearch.controller;

import com.example.ecomsearch.dto.ProductSearchRequest;
import com.example.ecomsearch.dto.ProductSearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.service.ProductSearchService;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductSearchService productSearchService;

    public ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public void indexProduct(@RequestBody Product product) throws IOException {
        productSearchService.indexProduct(product);
    }

    @PostMapping("/bulk")
    @ResponseStatus(HttpStatus.CREATED)
    public void bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        productSearchService.bulkIndexProducts(products);
    }

    @PostMapping("/search")
    public ProductSearchResponse search(@RequestBody ProductSearchRequest request) throws IOException {
        return productSearchService.search(request);
    }
}

package com.example.ecomsearch.controller;

